SELECT installation_key,release_code,module_version,execution_mode,contract_locked,external_actions_enabled,metadata->>'currentPhase' AS current_phase,metadata->>'propagationAutopilot' AS propagation_autopilot,metadata->>'transactionalOutbox' AS transactional_outbox FROM public.revenue_os_installations WHERE installation_key='revenue-command-os';
SELECT count(*) AS execution_tables FROM information_schema.tables WHERE table_schema='public' AND table_name IN ('revenue_os_propagation_packages','revenue_os_propagation_runs','revenue_os_adapter_registry','revenue_os_adapter_configs','revenue_os_adapter_health','revenue_os_execution_actions','revenue_os_execution_action_attempts','revenue_os_execution_outbox','revenue_os_execution_inbox','revenue_os_execution_idempotency','revenue_os_execution_approvals','revenue_os_execution_results','revenue_os_external_references','revenue_os_execution_failures','revenue_os_execution_dead_letters','revenue_os_execution_retries','revenue_os_execution_compensations','revenue_os_execution_rollbacks','revenue_os_execution_webhook_events','revenue_os_execution_state_transitions','revenue_os_campaign_propagations','revenue_os_wave_propagations','revenue_os_account_propagations','revenue_os_task_propagations','revenue_os_meeting_propagations','revenue_os_proposal_propagations','revenue_os_payment_propagations','revenue_os_delivery_handoffs','revenue_os_renewal_propagations','revenue_os_propagation_audit_events');
SELECT count(*) AS mandatory_adapters FROM public.revenue_os_adapter_registry WHERE mandatory=true;
SELECT adapter_code,label,transport,status,external_capable FROM public.revenue_os_adapter_registry ORDER BY adapter_code;
SELECT count(*) FILTER(WHERE external_action=true AND status='succeeded') AS external_actions_executed,count(*) FILTER(WHERE status='dead_letter') AS dead_letters,count(*) FILTER(WHERE status='awaiting_approval') AS awaiting_approval FROM public.revenue_os_execution_actions;
DO $$ BEGIN
 IF NOT EXISTS(SELECT 1 FROM public.revenue_os_installations WHERE installation_key='revenue-command-os' AND release_code='AC-REVENUE-OS-MZ14-PROPAGATION-AUTOPILOT' AND external_actions_enabled=false) THEN RAISE EXCEPTION 'MZ14 registry verification failed'; END IF;
 IF (SELECT count(*) FROM public.revenue_os_adapter_registry WHERE mandatory=true)<>16 THEN RAISE EXCEPTION 'MZ14 adapter verification failed'; END IF;
 IF (SELECT count(*) FROM information_schema.tables WHERE table_schema='public' AND table_name LIKE 'revenue_os_%')<1 THEN RAISE EXCEPTION 'Revenue OS tables unavailable'; END IF;
END $$;
